433:	private cleanupReadingRangeChildrenInNode(node: HTMLElement): void {
434:		const hasAnyEmbeds =
435:			node.matches?.(".internal-embed.markdown-embed") || node.querySelector?.(".internal-embed.markdown-embed") !== null;
436:		if (!hasAnyEmbeds) return;
437:
438:		const embeds = node.matches?.(".internal-embed.markdown-embed")
439:			? [node]
440:			: Array.from(node.querySelectorAll<HTMLElement>(".internal-embed.markdown-embed"));
