456:			const liveChild = this.livePreviewRangeChildByEmbed.get(embedEl);
457:			if (liveChild) {
458:				this.debugLog("live-preview:unload", embedEl.getAttribute("src"));
459:				try {
460:					liveChild.unload();
461:				} catch {
462:					// ignore
463:				} finally {
464:					this.livePreviewRangeChildByEmbed.delete(embedEl);
465:					this.livePreviewRangeChildren.delete(liveChild);
466:				}
467:			}
