490:	private ensureReadingRangeEmbedChild(embedEl: HTMLElement, sourcePath: string | null, origin: string): void {
491:		if (this.readingRangeChildByEmbed.has(embedEl)) return;
492:		if (!embedEl.isConnected) return;
493:		if (embedEl.closest(".markdown-source-view")) {
494:			this.debugSkip(embedEl, "reading:skip:source-view", { origin });
495:			return;
496:		}
497:		if (embedEl.classList.contains(INLINE_EDIT_ACTIVE_CLASS)) {
498:			this.debugSkip(embedEl, "reading:skip:inline-edit-active", { origin });
499:			return;
500:		}
501:		if (this.leaves.isNestedWithinEmbed(embedEl)) {
502:			this.debugSkip(embedEl, "reading:skip:nested", { origin });
503:			return;
504:		}
505:		if (embedEl.classList.contains(READING_RANGE_ACTIVE_CLASS)) return;
506:
507:		const resolvedSourcePath =
508:			sourcePath ?? this.getSourcePathForEmbedElement(embedEl) ?? this.plugin.app.workspace.getActiveFile()?.path ?? "";
509:
510:		const parsed = this.parseRangeEmbedForReading(embedEl, resolvedSourcePath);
511:		if (!parsed) {
512:			const src = embedEl.getAttribute("src") ?? "";
513:			const alt = embedEl.getAttribute("alt") ?? "";
514:			if (/#\^([a-z0-9_]+)-\1$/i.test(src.split("|")[0]) || /\^([a-z0-9_]+)-\1$/i.test(alt)) {
515:				this.debugSkip(embedEl, "reading:skip:parse-failed", {
516:					origin,
517:					src,
518:					alt,
519:					sourcePath: resolvedSourcePath,
520:				});
521:			}
522:			return;
523:		}
524:
525:		this.debugLog("reading:attach", {
526:			origin,
527:			src: embedEl.getAttribute("src"),
528:			alt: embedEl.getAttribute("alt"),
529:			sourcePath: resolvedSourcePath,
530:			file: parsed.file.path,
531:			subpath: parsed.subpath,
532:		});
533:
534:		const child = new ReadingRangeEmbedChild({
535:			plugin: this.plugin,
536:			embedEl,
537:			file: parsed.file,
538:			subpath: parsed.subpath,
539:			registerEmbed: this.registerReadingRangeEmbed.bind(this),
540:			unregisterEmbed: this.unregisterReadingRangeEmbed.bind(this),
541:		});
542:
543:		this.readingRangeChildByEmbed.set(embedEl, child);
544:		this.readingRangeChildren.add(child);
545:		child.register(() => {
546:			this.readingRangeChildren.delete(child);
547:			this.readingRangeChildByEmbed.delete(embedEl);
548:		});
549:
550:		child.load();
551:	}
