573:			const alt = embedEl.getAttribute("alt") ?? "";
574:			if (/#\^([a-z0-9_]+)-\1$/i.test(src.split("|")[0]) || /\^([a-z0-9_]+)-\1$/i.test(alt)) {
575:				this.debugSkip(embedEl, "live-preview:skip:parse-failed", {
576:					origin,
577:					src,
